/**
 * Canonical browser-safe installation-state read-model contracts.
 */
/**
 * Empty / first-run data types — everything the first-run screen renders.
 * Extends canonical map contracts: Task, scopes, git facts, RepoInfo
 * and SyncFreshness are imported, never duplicated.
 *
 * SIGNAL DISCIPLINE (same hard rule as types.ts / panel-types.ts /
 * conflict-types.ts): every field must be derivable from the signal
 * inventory only —
 *   1. installer step results — each install step (decision-project-025:
 *      hooks / MCP registration / local DB) is a local CLI action whose
 *      exit code + stderr are facts. `status`, `failure.reason` and
 *      `failure.fix` come from THERE, never invented.
 *   2. git facts — `git ls-files | wc -l` at connect time (the packing
 *      denominator), remote/branch facts.       → decision-github-002
 *   3. Claude Code hook events — PostToolUse Edit/Write file paths that
 *      match NO distillation anchor are what "uncategorized footprint"
 *      means; Notification/Stop drive task states. → decision-project-016/021
 *   4. local process facts — the `claude -p` mapping pass has a start time
 *      and an exit; that is ALL we know about it (no progress fraction,
 *      hence no percent anywhere — elapsed time only).
 *   5. user's own declarations at launch (scope r/w). → decision-project-020
 *
 * NO invented fields: no install progress %, no mapping ETA, no "expected
 * repo size" — honesty beats pretty (LOOP.md guideline 4).
 *
 * DERIVED, NEVER STORED (same principle as the milestone tier in
 * panel-types.ts): footprint GEOMETRY — areaFrac, sqrt damping, shelf
 * position, overflow collapse — is a pure function of
 * (footprints, repoFiles, territory rect) and lives in ./install-derive.ts.
 * Snapshots store only the mechanical facts (taskId, filesTouched,
 * firstSeenAt); a stored rect could contradict the rule.
 */
import type { RepoInfo, SyncFreshness, Task } from "./map-types.js";
/**
 * Step status. SOURCE: installer CLI exit codes — a step is "done" when its
 * command exited 0, "failed" when it exited non-zero, "now" while the
 * process runs, "pending" before it starts. Text pill first ("done" /
 * "now" / "failed" in mono), color reinforces.
 */
export type InstallStepStatus = "pending" | "now" | "done" | "failed";
/**
 * Why a step failed — verbatim from the installer's stderr, never
 * synthesized. Steps are independent: one failure does NOT stop the others
 * (S2 `install-failed`: hooks fail, MCP + DB still complete — honest
 * partial success), and Retry reruns ONLY the failed step.
 */
export interface InstallStepFailure {
    /**
     * One human clause, e.g. "isn't writable" — the installer's own error,
     * rendered after the codeRef chip ("~/.claude/settings.json isn't
     * writable").
     */
    reason: string;
    /**
     * The concrete path/identifier the failure is about, rendered as a mono
     * code chip. From the installer's stderr (it names what it touched).
     */
    codeRef: string;
    /**
     * Remediation line, verbatim from the installer's stderr when it emits
     * one (e.g. "chmod u+w ~/.claude/settings.json"). Travels in the
     * reason row's tooltip. Absent when the installer offered none.
     */
    fix?: string;
}
/**
 * One row of the install checklist. GENERAL shape (iter-15 S2 note:
 * per-step status + optional failure, NOT a bespoke hooks-only shape) —
 * the same row language renders a failed MCP or DB step unchanged.
 */
export interface InstallStep {
    /**
     * Stable step id. decision-project-025's install has exactly three:
     * "hooks" (Claude Code hooks into settings.json), "mcp" (register the
     * Vibehub MCP server), "db" (create the local SQLite file). Kept as
     * string so the shape survives installer changes.
     */
    id: string;
    /** Row label, e.g. "Installs hooks for Claude Code". Installer manifest. */
    label: string;
    status: InstallStepStatus;
    /** Present iff status === "failed". */
    failure?: InstallStepFailure;
}
/**
 * Moment A: nothing is watched, nothing is claimed. The titlebar shows the
 * quiet "No repo connected"; the rail shows the dashed true-empty
 * placeholder; the canvas shows the connect card.
 */
export interface RepoConnectionNone {
    kind: "none";
}
/**
 * Moment A′/A″: the user picked a folder and the three install steps are
 * running (or one has failed). The CTA is replaced by the picked path.
 */
export interface RepoConnectionConnecting {
    kind: "connecting";
    /**
     * Absolute path of the picked folder — from the system folder picker.
     * UI truncates with a LEADING ellipsis (the tail identifies the repo);
     * full path in the tooltip.
     */
    repoPath: string;
    /** The checklist, in install order. */
    steps: InstallStep[];
}
/**
 * Moment B onward: all steps done. The DB-creation step's scan captures
 * `repoFiles` as a first-class fact (S3 answer to the S2 open question 1).
 */
export interface RepoConnectionConnected {
    kind: "connected";
    /** Absolute path of the connected repo (folder picker, now on disk). */
    repoPath: string;
    /**
     * `git ls-files | wc -l` at connect time — the packing denominator for
     * uncategorized footprints (iter-15 rule). A mechanical git fact stored
     * by the DB-creation scan; no invented "repo size".
     */
    repoFiles: number;
    /**
     * NEVER-YET on this screen, enforced at the type level: the first-run
     * screen ends the moment a mapping pass completes, so a connected repo
     * here has by definition never been mapped. When distillation ships,
     * widen to `string` (ISO 8601 of the last completed pass).
     */
    mappedAt?: never;
}
export type RepoConnection = RepoConnectionNone | RepoConnectionConnecting | RepoConnectionConnected;
/**
 * State of the `claude -p` mapping pass (decision-project-025's ONLY
 * user-initiated knowledge action). SOURCE: local process facts — start
 * time and exit. We hold NO honest progress fraction, so the UI shows
 * elapsed time only (mono, no spinner arc, no percent).
 */
export type MappingRun = {
    kind: "none";
} | {
    kind: "running";
    /** When the pass was started (ISO 8601, local process fact). */
    startedAt: string;
} | {
    kind: "done";
    /** When the pass was started (ISO 8601, local process fact). */
    startedAt: string;
    /**
     * Process exit time (ISO 8601). On THIS screen "done" never renders
     * — the first-run screen ends when mapping completes — but the fact
     * type exists so the union is total.
     */
    finishedAt: string;
};
/**
 * Pre-mapping scope declarations have no territory to point at, so they
 * point at this sentinel — the full-bleed UNCATEGORIZED gray IS the one
 * implicit territory of an unmapped repo ("every file lives here until
 * the repo is mapped"). Keeps ScopeDeclaration.territoryId required
 * (types.ts unchanged) without faking a distilled territory.
 */
export declare const UNCATEGORIZED_TERRITORY_ID = "uncategorized";
/**
 * One session's footprint on the unmapped gray — the near-cousin of a
 * sub-block, except NOTHING semantic is known about it: no feature name
 * (the task's own title is the only honest label), no anchors.
 *
 * SOURCE: PostToolUse hook events whose Edit/Write file paths match no
 * distillation anchor (pre-mapping: ALL of them). Counted per session.
 *
 * Geometry is DERIVED (install-derive.ts packFootprints), never stored.
 */
export interface UncategorizedFootprint {
    /** The session that made it (id into InstallSnapshot.tasks). */
    taskId: string;
    /** Distinct files edited this session (PostToolUse path count). */
    filesTouched: number;
    /**
     * When the first uncategorized edit landed (ISO 8601, hook event
     * timestamp). Packing sorts oldest-first (launch order) and the
     * overflow ladder collapses the OLDEST into "+N earlier sessions".
     */
    firstSeenAt: string;
    /**
     * The first few distinct edited paths, in first-edit order — feeds the
     * tooltip ("has edited 3 files this session: src/health/endpoint.ts, …").
     * Mechanical PostToolUse paths, capped at capture time; the count above
     * is the first channel, this is detail-on-demand. Absent when the
     * capture kept none.
     */
    sampleFiles?: string[];
}
/**
 * Everything the first-run screen needs to render one frame.
 * Exactly one of the S2 variants per snapshot; the variant is fully
 * implied by the data (connection kind × steps × mapping × tasks), never
 * stored as a name.
 */
export interface InstallSnapshot {
    /** The "now" of this snapshot (ISO 8601) — all relative ages derive from it. */
    capturedAt: string;
    connection: RepoConnection;
    mapping: MappingRun;
    /**
     * Git facts for the titlebar repo chip — present iff connected
     * (pre-connect there is no repo to describe).
     */
    repo?: RepoInfo;
    /** Sync freshness — present iff connected (nothing syncs before that). */
    sync?: SyncFreshness;
    /**
     * Pre-mapping tasks (map Task reused verbatim; scopes point at
     * UNCATEGORIZED_TERRITORY_ID). Empty before the first session.
     */
    tasks: Task[];
    /** One per task that has edited files. Empty until the first edit lands. */
    footprints: UncategorizedFootprint[];
}
